from dataclasses import dataclass


@dataclass(frozen=True)
class Link:
    target: str
    relations: tuple[str, ...]


def parse_link_header(value: str) -> tuple[Link, ...]:
    links = []
    for entry in value.split(","):
        parts = [part.strip() for part in entry.split(";")]
        if not parts or not parts[0].startswith("<"):
            continue
        if not parts[0].endswith(">"):
            continue

        relations = ()
        for parameter in parts[1:]:
            name, separator, raw = parameter.partition("=")
            if separator and name.strip().lower() == "rel":
                relations = tuple(
                    raw.strip().strip('\"').split()
                )
        links.append(Link(parts[0][1:-1], relations))
    return tuple(links)


def link_for_relation(value: str, relation: str) -> str | None:
    wanted = relation.lower()
    for link in parse_link_header(value):
        if any(item.lower() == wanted for item in link.relations):
            return link.target
    return None

