from link_header import Link, link_for_relation, parse_link_header
from page_client import collect_items


def test_parser_reads_simple_absolute_relations():
    value = (
        '<https://api.example.test/catalog?page=2>; rel="next", '
        '<https://api.example.test/catalog?page=1>; rel="prev"'
    )

    assert parse_link_header(value) == (
        Link("https://api.example.test/catalog?page=2", ("next",)),
        Link("https://api.example.test/catalog?page=1", ("prev",)),
    )
    assert link_for_relation(value, "NEXT") == (
        "https://api.example.test/catalog?page=2"
    )


def test_collection_follows_an_absolute_next_page():
    pages = {
        "https://api.example.test/catalog?page=1": (
            '{"items": [{"id": 1}]}',
            {
                "Link": (
                    '<https://api.example.test/catalog?page=2>; rel="next"'
                )
            },
        ),
        "https://api.example.test/catalog?page=2": (
            '{"items": [{"id": 2}]}',
            {},
        ),
    }

    assert collect_items(
        "https://api.example.test/catalog?page=1", pages.__getitem__
    ) == ({"id": 1}, {"id": 2})
